  "description": "2027年國中教育會考倒數計時，包含 Gemini 驅動的每日激勵與學習建議功能。"
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

export interface MotivationResponse {
  text: string;
}

export enum LoadingState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

// 116 CAP Date: May 22, 2027
// Assuming start time is 08:20 AM (Exam prep usually starts around then)
export const TARGET_DATE = new Date('2027-05-22T08:20:00');

export const EXAM_NAME = "116年國中教育會考";
export const EXAM_DATES = "2027/05/22 ~ 05/23";

export const MOTIVATION_PROMPT = `
你是一位溫暖且充滿智慧的學習導師。請為一位正在準備「116年國中教育會考」的台灣國中生，提供一句簡短、有力且具體的學習建議或心靈雞湯。
重點放在：堅持、效率、心態調整或學科準備技巧。
字數限制：50字以內。
語言：繁體中文（台灣用語）。
語氣：正向、鼓勵、不說教。
`;

import { GoogleGenAI } from "@google/genai";
import { MOTIVATION_PROMPT } from '../constants';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const fetchMotivation = async (): Promise<string> => {
  if (!apiKey) {
    return "請設定 API Key 以獲取 AI 建議。";
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: MOTIVATION_PROMPT,
      config: {
        temperature: 0.7,
      }
    });

    return response.text || "加油！今天的努力是為了明天的成就。";
  } catch (error) {
    console.error("Error fetching motivation:", error);
    return "保持專注，你一定做得到！";
  }
};

import React, { useState, useEffect } from 'react';
import { TimeLeft } from '../types';
import { TARGET_DATE } from '../constants';

const CountdownTimer: React.FC = () => {
  const calculateTimeLeft = (): TimeLeft => {
    const difference = +TARGET_DATE - +new Date();

    if (difference > 0) {
      return {
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60),
      };
    }

    return { days: 0, hours: 0, minutes: 0, seconds: 0 };
  };

  const [timeLeft, setTimeLeft] = useState<TimeLeft>(calculateTimeLeft());

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const TimeUnit: React.FC<{ value: number; label: string }> = ({ value, label }) => (
    <div className="flex flex-col items-center mx-2 sm:mx-4">
      <div className="bg-white/20 backdrop-blur-md border border-white/30 rounded-xl p-4 sm:p-6 w-20 sm:w-32 h-24 sm:h-36 flex items-center justify-center shadow-lg transform transition-transform hover:scale-105">
        <span className="text-4xl sm:text-6xl font-bold text-white tabular-nums drop-shadow-md">
          {value.toString().padStart(2, '0')}
        </span>
      </div>
      <span className="mt-2 text-sm sm:text-base text-blue-100 font-medium tracking-wider uppercase">
        {label}
      </span>
    </div>
  );

  return (
    <div className="flex flex-wrap justify-center items-center py-8">
      <TimeUnit value={timeLeft.days} label="天" />
      <TimeUnit value={timeLeft.hours} label="時" />
      <TimeUnit value={timeLeft.minutes} label="分" />
      <TimeUnit value={timeLeft.seconds} label="秒" />
    </div>
  );
};

export default CountdownTimer;

import React, { useState } from 'react';
import { fetchMotivation } from '../services/geminiService';
import { LoadingState } from '../types';

const MotivationCard: React.FC = () => {
  const [motivation, setMotivation] = useState<string>("");
  const [status, setStatus] = useState<LoadingState>(LoadingState.IDLE);

  const getMotivation = async () => {
    setStatus(LoadingState.LOADING);
    try {
      const text = await fetchMotivation();
      setMotivation(text);
      setStatus(LoadingState.SUCCESS);
    } catch (e) {
      setMotivation("暫時無法連接到 AI 導師，但請相信你自己！");
      setStatus(LoadingState.ERROR);
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto mt-8 px-4">
      <div className="bg-white/10 backdrop-blur-lg border border-white/20 rounded-2xl p-6 sm:p-8 shadow-xl text-center">
        <h3 className="text-xl font-semibold text-white mb-4 flex items-center justify-center gap-2">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-yellow-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
          AI 學習導師
        </h3>

        <div className="min-h-[80px] flex items-center justify-center mb-6">
          {status === LoadingState.LOADING ? (
            <div className="flex items-center space-x-2">
              <div className="w-3 h-3 bg-white rounded-full animate-bounce"></div>
              <div className="w-3 h-3 bg-white rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
              <div className="w-3 h-3 bg-white rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
            </div>
          ) : (
            <p className="text-lg sm:text-xl text-white/90 font-medium leading-relaxed italic">
              {motivation || "點擊下方按鈕，獲取今日的專屬學習建議。"}
            </p>
          )}
        </div>

        <button
          onClick={getMotivation}
          disabled={status === LoadingState.LOADING}
          className="group relative inline-flex items-center justify-center px-8 py-3 text-base font-medium text-blue-900 bg-yellow-400 rounded-full hover:bg-yellow-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-yellow-400 transition-all duration-300 shadow-lg disabled:opacity-70 disabled:cursor-not-allowed"
        >
          <span className="absolute w-full h-full rounded-full opacity-0 group-hover:animate-ping bg-yellow-400"></span>
          <span className="relative flex items-center gap-2">
            {status === LoadingState.IDLE ? "給我一點能量" : "再來一個建議"}
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 transition-transform group-hover:translate-x-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </span>
        </button>
      </div>
    </div>
  );
};

export default MotivationCard;

