        <div className="p-6 border-t border-white/10 bg-slate-900/50">
           <p className="text-xs text-slate-400 text-center leading-relaxed">
             堅持到底<br/>夢想就在眼前
           </p>
        </div>
      </div>
    </>
  );
};

