import React, { useState, useEffect } from 'react';
import { motivationQuotes } from '../quotes';

const MotivationCard: React.FC = () => {
  const [quote, setQuote] = useState<string>("");

  useEffect(() => {
    // Calculate a stable index based on the current date (Taipei Time usually matches client time for this purpose)
    const now = new Date();
    // Reset to start of day to ensure consistency throughout the day
    const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    // Use a simple hash of the date string to pick a quote
    // This ensures that even if we reload, the quote is the same for the day
    // But different days get different quotes
    const dayString = startOfDay.toISOString().split('T')[0];

    let hash = 0;
    for (let i = 0; i < dayString.length; i++) {
      hash = ((hash << 5) - hash) + dayString.charCodeAt(i);
      hash |= 0; // Convert to 32bit integer
    }

    // Ensure positive index
    const index = Math.abs(hash) % motivationQuotes.length;
    setQuote(motivationQuotes[index]);
  }, []);

  const handleRandomQuote = () => {
    const randomIndex = Math.floor(Math.random() * motivationQuotes.length);
    setQuote(motivationQuotes[randomIndex]);
  };

  return (
    <div className="w-full max-w-2xl mx-auto mt-8 px-4">
      <div className="bg-white/10 backdrop-blur-lg border border-white/20 rounded-2xl p-6 sm:p-8 shadow-xl text-center">
        <h3 className="text-xl font-semibold text-white mb-4 flex items-center justify-center gap-2">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-yellow-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
          每日學習激勵
        </h3>

        <div className="min-h-[80px] flex items-center justify-center mb-6">
          <p className="text-lg sm:text-xl text-white/90 font-medium leading-relaxed italic animate-fade-in">
            {quote || "正在為你尋找力量..."}
          </p>
        </div>

        <button
          onClick={handleRandomQuote}
          className="group relative inline-flex items-center justify-center px-6 py-2 text-sm font-medium text-blue-900 bg-yellow-400/90 rounded-full hover:bg-yellow-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-yellow-400 transition-all duration-300 shadow-lg"
        >
          <span className="relative flex items-center gap-2">
            隨機再抽一張
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 transition-transform group-hover:rotate-180 duration-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </span>
        </button>
      </div>
    </div>
  );
};

