import React, { useState, useEffect } from 'react';
import { SCHEDULE_ITEMS } from '../constants';
import { ScheduleItem } from '../types';

const NextEvent: React.FC = () => {
  const [nextEvent, setNextEvent] = useState<ScheduleItem | null>(null);
  const [timeLeft, setTimeLeft] = useState<{days: number, hours: number, minutes: number} | null>(null);

  useEffect(() => {
    const calculateNextEvent = () => {
      const now = new Date();
      // Filter events with valid dateObj and in the future
      const futureEvents = SCHEDULE_ITEMS.filter(item => 
        item.dateObj && item.dateObj.getTime() > now.getTime()
      ).sort((a, b) => (a.dateObj!.getTime() - b.dateObj!.getTime()));

      if (futureEvents.length > 0) {
        const event = futureEvents[0];
        setNextEvent(event);

        const diff = event.dateObj!.getTime() - now.getTime();
        setTimeLeft({
          days: Math.floor(diff / (1000 * 60 * 60 * 24)),
          hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
          minutes: Math.floor((diff / 1000 / 60) % 60),
        });
      } else {
        setNextEvent(null);
        setTimeLeft(null);
      }
    };

    calculateNextEvent();
    const timer = setInterval(calculateNextEvent, 1000); // Update every second

    return () => clearInterval(timer);
  }, []);

  if (!nextEvent || !timeLeft) return null;

  return (
    <div className="w-full max-w-2xl mx-auto px-4">
      <div className="bg-gradient-to-r from-indigo-900/40 to-blue-900/40 backdrop-blur-md border border-indigo-400/30 rounded-2xl p-6 shadow-lg flex flex-col sm:flex-row items-center justify-between gap-6 transition-all hover:border-indigo-400/50">
        <div className="flex-1 text-center sm:text-left">
          <div className="text-blue-300 text-xs font-bold uppercase tracking-widest mb-2 flex items-center justify-center sm:justify-start gap-2">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
            </span>
            下一個重要日程
          </div>
          <h3 className="text-xl sm:text-2xl font-bold text-white tracking-wide mb-1">{nextEvent.task}</h3>
          <p className="text-sm text-blue-200/60 font-medium">{nextEvent.date}</p>
        </div>

        <div className="flex items-center gap-3 bg-black/20 p-3 rounded-xl border border-white/5">
             <div className="flex flex-col items-center min-w-[60px]">
                <span className="text-2xl sm:text-3xl font-bold text-yellow-400 tabular-nums leading-none">{timeLeft.days}</span>
                <span className="text-[10px] text-blue-300 font-medium uppercase mt-1">天</span>
             </div>
             <div className="h-8 w-[1px] bg-white/10"></div>
              <div className="flex flex-col items-center min-w-[60px]">
                <span className="text-2xl sm:text-3xl font-bold text-white tabular-nums leading-none">{timeLeft.hours}</span>
                <span className="text-[10px] text-blue-300 font-medium uppercase mt-1">時</span>
             </div>
        </div>
      </div>
    </div>
  );
};

