import React, { useState, useEffect } from 'react';
import { TimeLeft } from '../types';
import { TARGET_DATE } from '../constants';

const CountdownTimer: React.FC = () => {
  const calculateTimeLeft = (): TimeLeft => {
    const difference = +TARGET_DATE - +new Date();

    if (difference > 0) {
      return {
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60),
      };
    }

    return { days: 0, hours: 0, minutes: 0, seconds: 0 };
  };

  const [timeLeft, setTimeLeft] = useState<TimeLeft>(calculateTimeLeft());

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const TimeUnit: React.FC<{ value: number; label: string; highlight?: boolean }> = ({ value, label, highlight }) => (
    <div className="flex flex-col items-center relative group">
      <div className={`
        relative w-20 sm:w-32 h-24 sm:h-36 flex items-center justify-center 
        rounded-2xl backdrop-blur-md transition-all duration-300
        ${highlight 
          ? 'bg-gradient-to-b from-cyan-500/10 to-blue-600/10 border border-cyan-500/30 shadow-[0_0_25px_rgba(6,182,212,0.15)]' 
          : 'glass-card hover:bg-white/10'
        }
      `}>
        <span className={`
          text-4xl sm:text-7xl font-bold tabular-nums tracking-tighter
          ${highlight 
            ? 'text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-blue-400 drop-shadow-[0_0_10px_rgba(34,211,238,0.5)]' 
            : 'text-white drop-shadow-lg'
          }
        `}>
          {value.toString().padStart(2, '0')}
        </span>

        {/* Decorative corner accents */}
        <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-white/20 rounded-tl-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-white/20 rounded-tr-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-white/20 rounded-bl-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-white/20 rounded-br-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
      </div>

      <span className="mt-3 text-xs sm:text-sm text-slate-400 font-medium tracking-[0.2em] uppercase">
        {label}
      </span>
    </div>
  );

  return (
    <div className="w-full flex flex-wrap justify-center items-center gap-4 sm:gap-8 px-2">
      <TimeUnit value={timeLeft.days} label="Days" highlight />
      <div className="hidden sm:block text-4xl text-white/20 font-light -mt-8">:</div>
      <TimeUnit value={timeLeft.hours} label="Hours" />
      <div className="hidden sm:block text-4xl text-white/20 font-light -mt-8">:</div>
      <TimeUnit value={timeLeft.minutes} label="Minutes" />
      <div className="hidden sm:block text-4xl text-white/20 font-light -mt-8">:</div>
      <TimeUnit value={timeLeft.seconds} label="Seconds" />
    </div>
  );
};

