import React, { useState, useEffect } from 'react';
import { SCHEDULE_ITEMS } from '../constants';
import { ScheduleItem } from '../types';

const NextEvent: React.FC = () => {
  const [nextEvent, setNextEvent] = useState<ScheduleItem | null>(null);
  const [timeLeft, setTimeLeft] = useState<{days: number, hours: number, minutes: number} | null>(null);

  useEffect(() => {
    const calculateNextEvent = () => {
      const now = new Date();
      const futureEvents = SCHEDULE_ITEMS.filter(item => 
        item.dateObj && item.dateObj.getTime() > now.getTime()
      ).sort((a, b) => (a.dateObj!.getTime() - b.dateObj!.getTime()));

      if (futureEvents.length > 0) {
        const event = futureEvents[0];
        setNextEvent(event);

        const diff = event.dateObj!.getTime() - now.getTime();
        setTimeLeft({
          days: Math.floor(diff / (1000 * 60 * 60 * 24)),
          hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
          minutes: Math.floor((diff / 1000 / 60) % 60),
        });
      } else {
        setNextEvent(null);
        setTimeLeft(null);
      }
    };

    calculateNextEvent();
    const timer = setInterval(calculateNextEvent, 1000); 
    return () => clearInterval(timer);
  }, []);

  if (!nextEvent || !timeLeft) return null;

  return (
    <div className="w-full max-w-4xl mx-auto px-4">
      <div className="glass-card rounded-2xl p-1 overflow-hidden">
        <div className="bg-slate-900/40 rounded-xl p-5 sm:p-6 flex flex-col sm:flex-row items-center justify-between gap-6">

          <div className="flex items-start gap-4 w-full sm:w-auto">
            <div className="hidden sm:flex h-12 w-12 rounded-full bg-emerald-500/20 items-center justify-center border border-emerald-500/30 text-emerald-300">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>

            <div className="flex-1">
              <div className="flex items-center gap-2 mb-1">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
                </span>
                <span className="text-xs font-bold text-emerald-400 uppercase tracking-widest">Upcoming Event</span>
              </div>
              <h3 className="text-xl font-bold text-white mb-1">{nextEvent.task}</h3>
              <p className="text-slate-400 text-sm font-medium">{nextEvent.date}</p>
            </div>
          </div>

          <div className="flex items-center gap-2 bg-slate-950/50 p-3 rounded-lg border border-white/5 w-full sm:w-auto justify-center">
             <div className="text-center px-4 border-r border-white/10 last:border-0">
                <span className="block text-2xl font-bold text-emerald-400 tabular-nums">{timeLeft.days}</span>
                <span className="text-[10px] text-slate-500 uppercase font-bold">Days</span>
             </div>
             <div className="text-center px-4">
                <span className="block text-2xl font-bold text-white tabular-nums">{timeLeft.hours}</span>
                <span className="text-[10px] text-slate-500 uppercase font-bold">Hours</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

