  return (
    <div className="h-full w-full">
      <div className="relative glass-card rounded-3xl p-8 sm:p-10 h-full flex flex-col justify-center items-center text-center overflow-hidden group hover:shadow-xl transition-all duration-500 border border-white/60 bg-white/40">

