import React, { useState, useEffect } from 'react';
import { TimeLeft } from '../types';
import { TARGET_DATE } from '../constants';

const CountdownTimer: React.FC = () => {
  const calculateTimeLeft = (): TimeLeft => {
    const difference = +TARGET_DATE - +new Date();

    if (difference > 0) {
      return {
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60),
      };
    }

    return { days: 0, hours: 0, minutes: 0, seconds: 0 };
  };

  const [timeLeft, setTimeLeft] = useState<TimeLeft>(calculateTimeLeft());

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const TimeUnit: React.FC<{ value: number; label: string; highlight?: boolean }> = ({ value, label, highlight }) => (
    <div className="flex flex-col items-center relative group">
      <div className={`
        relative w-20 sm:w-32 h-24 sm:h-36 flex items-center justify-center 
        rounded-2xl backdrop-blur-md transition-all duration-300
        ${highlight 
          ? 'bg-gradient-to-b from-blue-50 to-white border border-blue-200 shadow-[0_10px_30px_rgba(59,130,246,0.15)]' 
          : 'glass-card hover:bg-white/90 shadow-lg hover:shadow-xl'
        }
      `}>
        <span className={`
          text-4xl sm:text-7xl font-bold tabular-nums tracking-tighter
          ${highlight 
            ? 'text-transparent bg-clip-text bg-gradient-to-b from-blue-600 to-blue-400 drop-shadow-sm' 
            : 'text-slate-700'
          }
        `}>
          {value.toString().padStart(2, '0')}
        </span>

        {/* Decorative corner accents - visible on hover */}
        <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-blue-300 rounded-tl-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-blue-300 rounded-tr-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-blue-300 rounded-bl-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-blue-300 rounded-br-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
      </div>

      <span className="mt-3 text-xs sm:text-sm text-slate-500 font-bold tracking-[0.2em] uppercase">
        {label}
      </span>
    </div>
  );

  return (
    <div className="w-full grid grid-cols-2 gap-x-4 gap-y-6 place-items-center px-8 sm:flex sm:flex-wrap sm:justify-center sm:items-center sm:gap-8 sm:px-2">
      <TimeUnit value={timeLeft.days} label="Days" highlight />
      <div className="hidden sm:block text-4xl text-slate-300 font-light -mt-8">:</div>
      <TimeUnit value={timeLeft.hours} label="Hours" />
      <div className="hidden sm:block text-4xl text-slate-300 font-light -mt-8">:</div>
      <TimeUnit value={timeLeft.minutes} label="Minutes" />
      <div className="hidden sm:block text-4xl text-slate-300 font-light -mt-8">:</div>
      <TimeUnit value={timeLeft.seconds} label="Seconds" />
    </div>
  );
};

