import React, { useState, useEffect } from 'react';
import { TimeLeft } from '../types';
import { TARGET_DATE } from '../constants';

const CountdownTimer: React.FC = () => {
  const calculateTimeLeft = (): TimeLeft => {
    const difference = +TARGET_DATE - +new Date();

    if (difference > 0) {
      return {
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60),
      };
    }

    return { days: 0, hours: 0, minutes: 0, seconds: 0 };
  };

  const [timeLeft, setTimeLeft] = useState<TimeLeft>(calculateTimeLeft());

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const TimerBlock = ({ value, label, colorClass, delay }: { value: number, label: string, colorClass: string, delay: number }) => (
    <div 
      className="flex flex-col items-center animate-fade-in"
      style={{ animationDelay: `${delay}ms` }}
    >
      <div className="relative group">
        <div className={`
          relative w-36 h-40 sm:w-40 sm:h-48 md:w-44 md:h-52
          flex flex-col items-center justify-center 
          rounded-[2rem] 
          bg-white/80 backdrop-blur-2xl 
          border border-white/60 
          shadow-[0_20px_40px_-12px_rgba(0,0,0,0.05)] 
          transition-all duration-500 ease-out
          hover:-translate-y-2 hover:shadow-[0_30px_60px_-15px_rgba(59,130,246,0.15)]
          overflow-hidden
        `}>

          {/* Top colored accent glow bar */}
          <div className={`absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r ${colorClass} opacity-80`}></div>

          {/* Ambient light glow behind the number */}
          <div className={`absolute -top-12 left-1/2 -translate-x-1/2 w-32 h-32 ${colorClass.replace('from-', 'bg-').split(' ')[0]} blur-[60px] opacity-20 group-hover:opacity-30 transition-opacity duration-500`}></div>

          {/* Number */}
